// Worked focus: http-ts-timeout-classification — Report which phase and policy ended an operation without exposing secrets or claiming the remote effect is known. Demonstrate the result through TypeScript 7 strict types plus WHATWG Fetch Request, Response, Headers, URL, streams, and AbortSignal contracts.
function worked_http_ts_timeouts_cancellation_3(remainingMs: number, phaseBudgetMs: number, cleanupReserveMs: number): { start: boolean; usableMs: number } {
  if (remainingMs <= 0 || phaseBudgetMs <= 0 || cleanupReserveMs < 0) {
    return { start: false, usableMs: 0 };
  }
  const usableMs = Math.min(phaseBudgetMs, Math.max(0, remainingMs - cleanupReserveMs));
  return { start: usableMs > 0, usableMs };
}

